mapper.select:
SELECT t1.id as taskId, t1.task_code taskCode, t1.required_completion_time requestDate, t1.end_detection_time finishDate, t2.report_code reportCode, t2.state state, t1.entrustment_id FROM test_task AS t1 LEFT JOIN test_report_record AS t2 ON t2.entrustment_id = t1.entrustment_id WHERE 1=1
and t1.dept_id = #{deptId}
and t1.required_completion_time >= #{requestDate}
and t1.end_detection_time >= #{finishDate}
and t1.start_detection_time >= #{startDate}
and t1.end_detection_time <= #{stopDate}
ORDER BY t1.task_code DESC

SELECT t2.NAME deptName, t2.CODE code, t3.NAME name, t3.user_id userId FROM test_technicist AS t1 LEFT JOIN test_team AS t2 ON t1.team_id = t2.id LEFT JOIN sys_user AS t3 ON t3.user_id = t1.user_id WHERE 1=1
and t2.id in
#{id}

SELECT id, entrustment_no, entrust_company, entrust_people, project_name, business_acceptor, acceptance_date, state FROM test_entrusted_info where 1=1
and acceptance_date >= #{startDate}
and acceptance_date <= #{stopDate}

SELECT id, inspector inspector, reviewer reviewer FROM test_task where 1=1
and start_detection_time >= #{startDate}
and end_detection_time <= #{stopDate}

SELECT id, inspector inspector, reviewer reviewer FROM test_task where 1=1
and review_time >= #{startDate}
and review_time <= #{stopDate}

SELECT id, verifyer_id verifyerId, issuer_id issuerId, sealer sealer FROM test_report_record where 1=1
and verifyer_time >= #{startDate}
and verifyer_time <= #{stopDate}

SELECT id, verifyer_id verifyerId, issuer_id issuerId, sealer sealer FROM test_report_record where 1=1
and issuer_time >= #{startDate}
and issuer_time <= #{stopDate}

SELECT t1.id as task_id, t1.task_code task_code, t1.required_completion_time requestDate, t1.end_detection_time finishDate, t2.report_code reportCode, t2.state report_state, t1.entrustment_id, t4.id sample_id, t4.sample_name , t5.id as itemId, t5.times, t5.unit_price, t5.check_item_name, t5.state item_state, t5.task_id item_task_id FROM test_task AS t1 LEFT JOIN test_report_record AS t2 ON t2.entrustment_id = t1.entrustment_id LEFT JOIN test_entrusted_sample_details_rel AS t3 ON t3.entrustment_id = t1.entrustment_id LEFT JOIN test_sample AS t4 ON t3.sample_id = t4.id LEFT JOIN test_entrusted_sample_checkitem_rel AS t5 ON t5.sample_id = t4.id WHERE 1=1
and t1.dept_id = #{deptId}
and t1.required_completion_time >= #{requestDate}
and t1.end_detection_time >= #{finishDate}
and t1.start_detection_time >= #{startDate}
and t1.end_detection_time <= #{stopDate}
ORDER BY t1.task_code DESC
